import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"二元圣镰","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/二元圣镰.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/二元圣镰.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/二元圣镰.md"};function p(_,e,l,i,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"二元圣镰",tabindex:"-1"},[n("二元圣镰 "),a("a",{class:"header-anchor",href:"#二元圣镰","aria-label":'Permalink to "二元圣镰"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="二元圣镰-1" tabindex="-1">二元圣镰 <a class="header-anchor" href="#二元圣镰-1" aria-label="Permalink to &quot;二元圣镰&quot;">​</a></h1><p>二元圣镰<br> C+1500<br> 武器伤害：12L<br> 武器特性：【猩红之力】【暗影炎】【回环之刃】<br> “一个古老的部族曾经敬此物为自然界平衡的典范...如今，它的纯洁早已被新吸收的泥沙和尘垢所污染...”<br> 史莱姆之神的身躯被撕裂，其中的一部分则被神匠用来制成了这把镰刀。<br> 这是一把长达4米的双头巨镰，正常具有巨镰武器基础模板的特性，其一端为象征腐化的幽紫，另一端则为象征血猩的绯红，中间的握把上遍布着如同血管一般柔软的纹路。</p><p>【回环之刃】:你可以使用一个标准动作，将这把镰刀以高速旋转的姿态朝敌方扔出，在飞行至距离自身15米的范围后，镰刀会自动飞回手中,这视为对路径上的敌人全部进行了一次白刃攻击，如同范围伤害一样处理。</p><p>【暗影炎】:当你使用回环之刃的攻击对敌人造成伤害后，腐化之力便会令敌人的身上燃烧暗影火焰，这会令敌人在当回合内的2点快速医疗失效。若没有快速医疗则在回合结束时额外造成2L火焰伤害。</p><p>【猩红之力】:当你使用回环之刃对敌人造成伤害后会立即为你提供【灵魂收割】状态，【灵魂收割】会在获得时你恢复1点严重或韧性伤害，在回合结束时失去这个状态，。<br> 【灵魂收割】的效果在回合内只会生效一次，这个效果需要你造成至少3点实际伤害才能激活。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const f=r(d,[["render",p]]);export{m as __pageData,f as default};
